from flask import Flask, request, render_template_string
from markupsafe import Markup, escape
import re

app = Flask(__name__)

ALLOWED_TAGS = {"b", "strong", "i", "em", "br"}

def sanitize_basic_formatting(text):
    if not text:
        return ""
    text = escape(text)
    text = str(text)

    def restore_tag(match):
        slash = match.group(1) or ""
        tag = match.group(2).lower()
        if tag in ALLOWED_TAGS:
            return Markup(f"<{slash}{tag}>")
        return match.group(0)

    pattern = re.compile(r"&lt;(/?)(\w+)&gt;")
    text = pattern.sub(restore_tag, text)
    return Markup(text)

